                new ApiParameterInfo(@"FilterPlaceholder", @"string?", null, @"Overrides the placeholder text shown in filter inputs.", null, false, false, false, @"FlareDataGrid"),
                new ApiParameterInfo(@"FooterContent", @"RenderFragment?", null, @"Custom content rendered in the footer area below the table (the toolbar's counterpart at the bottom). Like ToolbarContent, child components placed here resolve the grid automatically via the cascade. Use it to position grid controls (e.g. a FlareDataGridPager) below the data.", null, false, false, false, @"FlareDataGrid"),
                new ApiParameterInfo(@"Grouping", @"RenderFragment?", null, @"Grouping levels, declared as nested DataGridGroup child components (outermost first). When present, rows are grouped into nested, collapsible sections with optional per-level or grid-level aggregates. The level keys also flow to a server provider via DataGridRequest.GroupKeys. <Grouping> <DataGridGroup Key=""Role"" Selector=""@(p => p.Role)"" /> <DataGridGroup Key=""City"" Selector=""@(p => p.City)"" /> </Grouping>", null, false, false, false, @"FlareDataGrid"),
                new ApiParameterInfo(@"Height", @"string", null, @"CSS height of the table container. Works with or without virtualization.", null, false, false, false, @"FlareDataGrid"),
