                new ApiParameterInfo(@"HiddenColumnsChanged", @"EventCallback<IReadOnlyCollection<string>>", null, @"Raised with the full set of hidden column keys whenever a column is shown or hidden.", null, false, true, false, @"FlareDataGrid"),
