                new ApiParameterInfo(@"InfiniteScroll", @"bool", null, @"Infinite scrolling: with an ItemsProvider, rows accumulate page by page as the user scrolls to the bottom (instead of pagination or a known-total virtual window). The provider is called with successive Page values; loading stops when a page returns fewer than PageSize rows or the reported total is reached.", null, false, false, false, @"FlareDataGrid"),
                new ApiParameterInfo(@"Items", @"IEnumerable<TItem?>?", null, @"In-memory data source bound to the grid.", null, false, false, false, @"FlareDataGrid"),
