                new ApiParameterInfo(@"OnPaste", @"EventCallback<DataGridPaste<TItem?>>", null, @"Raised on Ctrl+V when CellSelection is enabled: the clipboard's tab-separated text is parsed and mapped onto the cells starting at the top-left of the current selection. The handler applies each cell's value to its row item (the grid cannot write through the read-only column accessors itself).", null, false, true, false, @"FlareDataGrid"),
